// What you write (JSX)
const element = <h1 className="title">Hello, world!</h1>;

// What the compiler produces (classic runtime)
const element = React.createElement(
  'h1',                        // type: string for host elements
  { className: 'title' },      // props object (null if no props)
  'Hello, world!'              // children (variadic, 3rd arg onward)
);

// React.createElement returns this plain object:
{
  $$typeof: Symbol(react.element),  // anti-XSS marker
  type: 'h1',                       // 'h1' for host, or Component for custom
  key: null,                        // key prop if provided
  ref: null,                        // ref prop if provided
  props: {
    className: 'title',
    children: 'Hello, world!'       // children moved into props
  },
  _owner: null,                     // internal: fiber that created this
}

// JSX
const card = (
  <div className="card">
    <h2>Title</h2>
    <p>Body text</p>
  </div>
);

// Compiled
const card = React.createElement(
  'div',
  { className: 'card' },
  React.createElement('h2', null, 'Title'),  // child 1
  React.createElement('p', null, 'Body text') // child 2
);

import Button from './Button';

// JSX
const el = <Button variant="primary" onClick={handleClick}>Save</Button>;

// Compiled — type is the Button reference, not a string
const el = React.createElement(
  Button,                         // reference to the component function
  { variant: 'primary', onClick: handleClick },
  'Save'
);

function myComponent() { return <p>text</p>; } // lowercase — BAD
function MyComponent() { return <p>text</p>; } // uppercase — GOOD

// <myComponent /> compiles to: createElement('myComponent', null)
// React sees a string, tries to find an HTML element named 'myComponent'
// → warning: unknown DOM element

// <MyComponent /> compiles to: createElement(MyComponent, null)
// React sees a function reference, calls it to produce JSX

// Classic runtime output (React < 17 / "jsx": "react" in tsconfig)
import React from 'react';  // must be in scope
const el = React.createElement('div', { id: 'app' }, 'Hello');

// Automatic runtime output (React 17+ / "jsx": "react-jsx" in tsconfig)
import { jsx as _jsx } from 'react/jsx-runtime'; // injected by compiler
const el = _jsx('div', { id: 'app', children: 'Hello' });
// children is in props, not a separate arg

// JSX with spread
function StyledButton({ className, ...rest }) {
  return <button className={`btn ${className}`} {...rest} />;
}

// Compiled (approximately)
function StyledButton({ className, ...rest }) {
  return React.createElement(
    'button',
    Object.assign({}, { className: `btn ${className}` }, rest)
  );
}

// JSX
const el = <input type={inputType} value={currentValue} onChange={handleChange} />;

// Compiled
const el = React.createElement('input', {
  type: inputType,
  value: currentValue,
  onChange: handleChange
});

// No children — props.children is undefined
<Image src="/logo.png" />
// createElement('Image', { src: '/logo.png' })

// Single text child — props.children is a string
<p>Hello</p>
// createElement('p', null, 'Hello')

// Multiple children — props.children is an array
<ul>
  <li>One</li>
  <li>Two</li>
</ul>
// createElement('ul', null,
//   createElement('li', null, 'One'),
//   createElement('li', null, 'Two')
// )

// Single component child — props.children is a React element
<Provider>
  <App />
</Provider>
// createElement(Provider, null, createElement(App, null))

// Mixed text and elements — props.children is an array
<p>Count: <strong>{n}</strong></p>
// createElement('p', null, 'Count: ', createElement('strong', null, n))

// Pure React.createElement — no JSX needed
import React from 'react';
import { createRoot } from 'react-dom/client';

function Counter({ initial }) {
  const [count, setCount] = React.useState(initial);
  return React.createElement(
    'div', null,
    React.createElement('p', null, `Count: ${count}`),
    React.createElement(
      'button',
      { onClick: () => setCount(c => c + 1) },
      'Increment'
    )
  );
}

createRoot(document.getElementById('root'))
  .render(React.createElement(Counter, { initial: 0 }));

// Each render of a list component creates N+1 element objects cheaply
function ItemList({ items }) {
  return React.createElement(
    'ul', null,
    ...items.map(item =>
      React.createElement('li', { key: item.id }, item.name)
      // Each call returns a tiny plain object — very cheap
    )
  );
  // React compares this new element tree with the previous one
  // and only updates DOM nodes whose attributes/text changed
}

// JSX
<li key={item.id} ref={itemRef} className="item">{item.name}</li>

// Compiled (classic runtime):
React.createElement(
  'li',
  { className: 'item', ref: itemRef, key: item.id }, // key/ref in props in classic
  item.name
);

// In the resulting React element object, key and ref are at the top level:
{
  $$typeof: Symbol(react.element),
  type: 'li',
  key: 'item-123',     // extracted from props
  ref: itemRef,        // extracted from props
  props: {
    className: 'item', // key and ref NOT here
    children: 'Name'
  }
}

// Adjacent expressions: comma-separated in createElement output
<p>
  Hello   world   !
</p>
// Whitespace is collapsed: renders "Hello world !"
// Newlines at start/end of a line are removed

// Text + expressions
<p>Count: {n}</p>
// createElement('p', null, 'Count: ', n)
// Note the space before { is preserved because it's part of 'Count: '

// Conditional rendering — false, null, undefined do not render
<div>
  {isLoading && <Spinner />}
  {error ? <ErrorMsg>{error}</ErrorMsg> : null}
</div>
// createElement('div', null,
//   isLoading && createElement(Spinner, null),
//   error ? createElement(ErrorMsg, null, error) : null
// )
// React skips false, null, undefined when rendering children

// Using Fragment to return siblings without a wrapper div
function DayHeader({ day, month }) {
  return (
    <>
      <h2>{day}</h2>
      <span className="month">{month}</span>
    </>
  );
}

// Compiles to:
function DayHeader({ day, month }) {
  return React.createElement(
    React.Fragment,
    null,
    React.createElement('h2', null, day),
    React.createElement('span', { className: 'month' }, month)
  );
}

// JSX assigned to a variable
const header = <h1>Welcome</h1>;

// JSX in an array
const items = ['a', 'b', 'c'].map((letter, i) => (
  <li key={i}>{letter}</li>
));

// JSX as a function return value
function renderMode(mode) {
  if (mode === 'dark') return <DarkTheme />;
  return <LightTheme />;
}

// JSX as an argument
ReactDOM.render(<App />, document.getElementById('root'));

// TERNARY inside JSX
const badge = (
  <span className={isAdmin ? 'badge-admin' : 'badge-user'}>
    {isAdmin ? 'Admin' : 'User'}
  </span>
);

// Function calls inside JSX children
function List({ items }) {
  return (
    <ul>
      {items.filter(Boolean).map(item => (
        <li key={item.id}>{item.label}</li>
      ))}
    </ul>
  );
}

{
  // tsconfig.json — TypeScript JSX settings
  "compilerOptions": {
    "jsx": "react-jsx",     // automatic runtime (React 17+, recommended)
    // "jsx": "react"       // classic runtime (requires import React)
    // "jsx": "preserve"    // leave JSX as-is (for bundlers to handle)
    "jsxImportSource": "react" // package for automatic runtime (default)
  }
}

// vite.config.js — Vite handles JSX via @vitejs/plugin-react (SWC or Babel)
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [
    react({
      jsxRuntime: 'automatic' // default for @vitejs/plugin-react
    })
  ]
});

const original = <Button color="blue">Click</Button>;

// createElement — always creates fresh
const fresh = React.createElement(Button, { color: 'red' }, 'Click');

// cloneElement — copies and merges props
const modified = React.cloneElement(original, { color: 'red' });
// Result: <Button color="red">Click</Button>
// Children are preserved from original unless you pass new ones

// Common use case: render prop / children augmentation
function Toolbar({ children }) {
  return (
    <div className="toolbar">
      {React.Children.map(children, child =>
        React.cloneElement(child, { size: 'sm' })
      )}
    </div>
  );
}
